import org.springframework.context.event.*;
import org.springframework.stereotype.*;
import org.springframework.web.client.RestTemplate;
import java.util.*;

@Service
public class GrafanaDeploymentAnnotator {
    private final RestTemplate restTemplate;
    private final String grafanaUrl;
    private final String grafanaApiKey;

    GrafanaDeploymentAnnotator(RestTemplate r) {
        this.restTemplate=r;
        // In production: inject from @Value
        this.grafanaUrl = 'http://grafana:3000';
        this.grafanaApiKey = System.getenv('GRAFANA_API_KEY');
    }

    @EventListener(org.springframework.boot.context.event.ApplicationStartedEvent.class)
    public void onDeployment(org.springframework.boot.context.event.ApplicationStartedEvent event) {
        // POST annotation to Grafana on every deployment:
        try {
            Map<String, Object> annotation = Map.of(
                'time',  System.currentTimeMillis(),
                'tags',  List.of('deployment', 'payment-service'),
                'text',  'Deployment: payment-service v' + getVersion()
            );
            restTemplate.postForObject(
                grafanaUrl + '/api/annotations',
                annotation, Map.class
            );
            System.out.println('[Grafana] Deployment annotation created');
        } catch (Exception e) {
            System.err.println('[Grafana] Failed to create annotation: ' + e.getMessage());
        }
    }

    private String getVersion() {
        return System.getProperty('app.version', 'unknown');
    }

    // VALUE:
    // Grafana dashboard shows a vertical line at T=19:05 with 'Deployment: payment-service v2.1'
    // Correlate: did error rate spike AFTER the deployment?
    // Root cause: 'yes, error rate went from 0.1% to 3% at deployment time'
    // Fix: roll back to v2.0

    public static void main(String[] a) {
        System.out.println('[Grafana] Deployment annotation: correlates code changes with metric changes');
    }
}

