import io.micrometer.core.instrument.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@Service
class MultiInstancePaymentTimer {
    private final Timer timer;
    MultiInstancePaymentTimer(MeterRegistry reg) {
        timer = Timer.builder("multi.payment.duration")
            .publishPercentileHistogram()   // ← generates _bucket metrics for histogram_quantile
            .minimumExpectedValue(java.time.Duration.ofMillis(1))
            .maximumExpectedValue(java.time.Duration.ofSeconds(10))
            .register(reg);
    }

    public void record(java.time.Duration d) { timer.record(d); }
}

// Correct PromQL for multi-instance p99:
// histogram_quantile(0.99,
//   sum(rate(multi_payment_duration_seconds_bucket[5m])) by (le)
// )
// → aggregates buckets across ALL instances → statistically correct

// application.yml alternative:
// management.metrics.distribution.percentiles-histogram.multi.payment.duration: true

@SpringBootTest
class HistogramTest {
    @Autowired MultiInstancePaymentTimer svc;
    @Autowired MeterRegistry reg;
    @Test void histogram_buckets_exist() {
        svc.record(java.time.Duration.ofMillis(150));
        // histogram_quantile needs _bucket metrics:
        assertFalse(reg.find("multi.payment.duration").timers().isEmpty(),
            "Timer should be registered");
        assertTrue(reg.find("multi.payment.duration").timer().count() >= 1);
    }
}

