// Stacked: shows relative contribution of each service to total page latency

public class FlipkartDashboard { public static void main(String[] a) { System.out.println("5 panels: latency, cache, errors, availability, breakdown"); } }

import io.micrometer.core.instrument.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.concurrent.atomic.AtomicInteger;
import java.time.Duration;

@Service
class RazorpayObsStack {
    private final MeterRegistry reg;
    private final Timer hist;
    private final AtomicInteger queueDepth=new AtomicInteger(0);

    RazorpayObsStack(MeterRegistry r) {
        reg=r;
        hist=Timer.builder("rp.obs.payment.duration")
            .publishPercentileHistogram()  // enables histogram_quantile in Prometheus
            .minimumExpectedValue(Duration.ofMillis(1))
            .maximumExpectedValue(Duration.ofSeconds(10))
            .register(reg);
        Gauge.builder("rp.obs.queue.depth",queueDepth,AtomicInteger::get).register(reg);
    }

    String processPayment(String gateway, double amount, boolean succeed) {
        queueDepth.incrementAndGet();
        try {
            return hist.record(()-> {
                String status=succeed?"success":"failure";
                reg.counter("rp.obs.payments","status",status,"gateway",gateway).increment();
                try{Thread.sleep(50);}catch(InterruptedException e){Thread.currentThread().interrupt();}
                return "PAY-"+status;
            });
        } finally { queueDepth.decrementAndGet(); }
    }
}

// DASHBOARD PROMQL:
// 1. Rate: rate(rp_obs_payments_total{status='success'}[5m])
// 2. Error%: sum(rate(rp_obs_payments_total{status='failure'}[5m])) / sum(rate(rp_obs_payments_total[5m])) * 100
// 3. P99 (correct): histogram_quantile(0.99, sum(rate(rp_obs_payment_duration_seconds_bucket[5m])) by (le))
// 4. Queue: rp_obs_queue_depth
// 5. Throughput by gateway: sum(rate(rp_obs_payments_total[5m])) by (gateway)

@SpringBootTest
class RazorpayObsStackTest{
    @Autowired RazorpayObsStack svc;
    @Autowired MeterRegistry reg;
    @Test void counter_registers(){svc.processPayment("visa",999.0,true);assertNotNull(reg.find("rp.obs.payments").tag("status","success").counter());}
    @Test void timer_registers(){svc.processPayment("mc",499.0,false);Timer t=reg.find("rp.obs.payment.duration").timer();assertNotNull(t);assertTrue(t.count()>=1);}
    @Test void gauge_registers(){svc.processPayment("upi",99.0,true);assertNotNull(reg.find("rp.obs.queue.depth").gauge());}
}
